import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.math.BigDecimal;
import java.math.RoundingMode;

/**
 * GRADE - pass/fail with a completion bonus, translated from COBOL 85.
 * Faithful variant: exact COBOL arithmetic behavior takes priority over
 * Java idiom. A score of 60 or more sets the pass flag (WS-PASS-FLAG :=
 * 1); the PASSING 88-level condition name is the test WS-PASS-FLAG = 1.
 * A passing student earns score * 2.50% ROUNDED half away from zero into
 * PIC 9(5)V99; a failing student earns nothing.
 */
public final class Grade {

    /** Pass threshold from MAIN-PARA: a score of 60 or more passes. */
    private static final BigDecimal PASS_MARK = new BigDecimal("60");

    /** The value the PASSING 88-level tests for (WS-PASS-FLAG = 1). */
    private static final BigDecimal PASS_TRUE = new BigDecimal("1");

    /** WS-BONUS-RATE PIC 9V99 VALUE 2.50 (percent). */
    private static final BigDecimal BONUS_RATE = new BigDecimal("2.50");

    /** WS-SCORE capacity PIC 9(3). */
    private static final BigDecimal PIC_9_3_MODULUS = new BigDecimal("1000");

    /** WS-BONUS capacity PIC 9(5)V99. */
    private static final BigDecimal PIC_9_5_V99_MODULUS = new BigDecimal("100000");

    public static void main(String[] args) throws IOException {
        BufferedReader in = new BufferedReader(new InputStreamReader(System.in));

        // MAIN-PARA (grade.cbl:29-32): ACCEPT + FUNCTION NUMVAL.
        String studentId = readLine(in);                                 // WS-STUDENT-ID PIC X(8)
        BigDecimal score = numval(readLine(in), 0, PIC_9_3_MODULUS);     // WS-SCORE PIC 9(3)

        // IF WS-SCORE >= 60 MOVE 1 ELSE MOVE 0 (grade.cbl:33-37).
        BigDecimal passFlag;
        if (score.compareTo(PASS_MARK) >= 0) {
            passFlag = new BigDecimal("1");
        } else {
            passFlag = new BigDecimal("0");
        }

        // IF PASSING (WS-PASS-FLAG = 1): COMPUTE WS-BONUS ROUNDED =
        // WS-SCORE * WS-BONUS-RATE / 100 (grade.cbl:38-42). The /100 is an
        // exact decimal shift; ROUNDED settles half away from zero.
        BigDecimal bonus;
        if (passFlag.compareTo(PASS_TRUE) == 0) {
            bonus = score.multiply(BONUS_RATE)
                    .movePointLeft(2)
                    .setScale(2, RoundingMode.HALF_UP)
                    .remainder(PIC_9_5_V99_MODULUS);
        } else {
            bonus = new BigDecimal("0.00");
        }

        // PRINT-PARA (grade.cbl:44-48): KEY=VALUE contract on stdout.
        StringBuilder out = new StringBuilder();
        out.append("STUDENT_ID=").append(studentId).append('\n');
        out.append("PASS=").append(passFlag.toPlainString()).append('\n');
        out.append("BONUS=").append(bonus.toPlainString()).append('\n');
        System.out.print(out);
    }

    private static String readLine(BufferedReader in) throws IOException {
        String line = in.readLine();
        return line == null ? "" : line.trim();
    }

    /**
     * FUNCTION NUMVAL followed by the COMPUTE store into the target
     * PICTURE: extra decimals truncate toward zero and integer digits
     * beyond the PICTURE's capacity drop silently. COBOL input-conversion
     * behavior with no ON SIZE ERROR declared.
     */
    private static BigDecimal numval(String s, int scale, BigDecimal capacity) {
        try {
            BigDecimal v = new BigDecimal(s.trim());
            if (v.signum() < 0) {
                throw new NumberFormatException("negative value for unsigned PICTURE");
            }
            return v.setScale(scale, RoundingMode.DOWN).remainder(capacity);
        } catch (NumberFormatException e) {
            System.err.println("GRADE: invalid numeric input: " + s);
            System.exit(3);
            return BigDecimal.ZERO; // unreachable
        }
    }
}
